    if (firstUserIndex >= 0) {
      scored[firstUserIndex].importance += 100;
    }
    if (lastUserIndex >= 0) {
      scored[lastUserIndex].importance += 200;
    }
    const sortedByImportance = [...scored].sort((a, b) => b.importance - a.importance);
    const selected = [];
    let usedTokens = 0;
