function normalizePath(path2) {
  let normalized = path2.replace(/\\/g, "/");
  normalized = normalized.replace(/\/+/g, "/");
  const parts = normalized.split("/");
  const result = [];
  for (const part of parts) {
    if (part === ".") {
      continue;
    }
    if (part === "..") {
      result.pop();
      continue;
    }
    if (part) {
      result.push(part);
    }
  }
  const prefix = normalized.startsWith("/") ? "/" : "";
  return prefix + result.join("/");
}
